{
  "claimant": "client_agent",
  "respondent": "freelancer_bot",
  "policy": "freelance-delivery",
  "claim": "Logo design never delivered",
  "desired_remedy": "full_refund",
  "contract": {
    "parties": ["client_agent", "freelancer_bot"],
    "obligations": ["Deliver logo design by June 20"],
    "deadlines": ["2026-06-20"]
  },
  "evidence": [
    {
      "type": "contract",
      "source": "agreement.pdf",
      "timestamp": "2026-06-01",
      "claimed_fact": "Logo design deliverable due June 20"
    },
    {
      "type": "log",
      "source": "email_thread.pdf",
      "timestamp": "2026-06-22",
      "claimed_fact": "No deliverable was submitted by the deadline"
    },
    {
      "type": "testimony",
      "source": "witness_statement",
      "timestamp": "2026-06-22",
      "claimed_fact": "The respondent never delivered any work"
    }
  ]
}

{
  "claimant": "developer",
  "respondent": "client",
  "policy": "milestone-payment",
  "claim": "Milestone completed but payment refused",
  "desired_remedy": "full_payment",
  "contract": {
    "parties": ["developer", "client"],
    "obligations": ["Pay milestone 2 upon completion"],
    "deadlines": ["2026-06-20"]
  },
  "metadata": {
    "milestone_completed": true,
    "milestone_progress_pct": 100,
    "days_since_completion": 7,
    "payment_terms_days": 0
  },
  "evidence": [
    {
      "type": "contract",
      "source": "agreement.pdf",
      "timestamp": "2026-06-01",
      "claimed_fact": "Milestone 2 payment due upon completion"
    },
    {
      "type": "testimony",
      "source": "acceptance.pdf",
      "timestamp": "2026-06-15",
      "claimed_fact": "Milestone 2 was accepted and completed"
    }
  ]
}

{
  "claimant": "client",
  "respondent": "saas_provider",
  "policy": "sla-monitoring",
  "claim": "SLA uptime violation",
  "desired_remedy": "service_credit",
  "contract": {
    "parties": ["client", "saas_provider"],
    "obligations": ["Maintain 99.9 percent uptime"],
    "deadlines": ["2026-06-30"],
    "payment_terms": "SLA requires 99.9 percent uptime"
  },
  "metadata": {
    "required_uptime": 99.9,
    "actual_uptime": 98.5,
    "max_latency": 200,
    "actual_latency": 450,
    "monitoring_period_confirmed": true
  },
  "evidence": [
    {
      "type": "contract",
      "source": "sla.pdf",
      "timestamp": "2026-06-01",
      "claimed_fact": "SLA requires 99.9 percent uptime"
    },
    {
      "type": "log",
      "source": "monitoring.json",
      "timestamp": "2026-06-22",
      "claimed_fact": "Actual uptime was 98.5 percent for June"
    }
  ]
}

{
  "claimant": "buyer_agent",
  "respondent": "weather_api",
  "policy": "api-quality",
  "claim": "API returned wrong data type",
  "desired_remedy": "full_refund",
  "contract": {
    "parties": ["buyer_agent", "weather_api"],
    "obligations": ["Return weather data matching OpenAPI schema"],
    "deadlines": ["2026-06-22"]
  },
  "metadata": {
    "response_received": true,
    "schema_matches": false,
    "mismatched_field": "temperature",
    "expected_type": "integer",
    "actual_type": "string"
  },
  "evidence": [
    {
      "type": "contract",
      "source": "openapi.json",
      "timestamp": "2026-06-01",
      "claimed_fact": "Schema declares temperature as integer"
    },
    {
      "type": "log",
      "source": "response.json",
      "timestamp": "2026-06-22",
      "claimed_fact": "API returned temperature as string"
    }
  ]
}

{
  "claimant": "shopping_agent",
  "respondent": "merchant_store",
  "policy": "physical-commerce",
  "claim": "Wrong product delivered",
  "desired_remedy": "full_refund",
  "contract": {
    "parties": ["shopping_agent", "merchant_store"],
    "obligations": ["Deliver correct product as ordered"],
    "deadlines": ["2026-06-25"]
  },
  "metadata": {
    "delivery_confirmed": true,
    "received_matches_order": false,
    "ordered_product": "Blue sneakers size 10",
    "received_product": "Red sneakers size 10"
  },
  "evidence": [
    {
      "type": "contract",
      "source": "order_receipt",
      "timestamp": "2026-06-20",
      "claimed_fact": "Ordered blue sneakers size 10"
    },
    {
      "type": "log",
      "source": "delivery_photo.jpg",
      "timestamp": "2026-06-22",
      "claimed_fact": "Received red sneakers wrong color"
    }
  ]
}
